async function buildUserMapping(supabase) {
  const { data: users, error } = await supabase.auth.admin.listUsers();

  if (error) {
    throw new Error(`Failed to fetch users: ${error.message}`);
  }

  const emailToUUID = new Map();
  users.users.forEach(user => {
    emailToUUID.set(user.email.toLowerCase(), user.id);
  });

  console.log(`Built user mapping for ${emailToUUID.size} users`);
  return emailToUUID;
}

findings.recommendation:
Add validation for empty user list and verify migration user exists:

if (error) {
  throw new Error(`Failed to fetch users: ${error.message}`);
}

if (!users || !users.users || users.users.length === 0) {
  throw new Error('No users found in auth.users - cannot map creators');
}

const emailToUUID = new Map();
users.users.forEach(user => {
  if (!user.email) {
    console.warn(`User ${user.id} has no email - skipping`);
    return;
  }
  emailToUUID.set(user.email.toLowerCase(), user.id);
});

// Verify migration user exists
const migrationEmail = 'migration@claritybusinesssolutions.ca';
if (!emailToUUID.has(migrationEmail)) {
  throw new Error(`Migration user ${migrationEmail} not found - create before running migration`);
}

console.log(`Built user mapping for ${emailToUUID.size} users`);
return emailToUUID;

