  // Check customers
  const { data: customer } = await supabase.from('customers')...
}

findings.recommendation:
Optimize by:
1. Pre-loading all parent entity IDs into Maps before transformation loop
2. Or use Promise.all to check all three tables in parallel:

const [projectResult, taskResult, customerResult] = await Promise.all([
  supabase.from('projects').select('id, organization_id').eq('id', fkId).maybeSingle(),
  supabase.from('tasks').select('id, project_id, projects!inner(organization_id)').eq('id', fkId).maybeSingle(),
  supabase.from('customers').select('id, organization_id').eq('id', fkId).maybeSingle()
]);

if (projectResult.data) return { entity_type: 'project', ... };
if (taskResult.data) return { entity_type: 'task', ... };
if (customerResult.data) return { entity_type: 'customer', ... };

This reduces 3N queries to N queries with 3 parallel lookups each.

